import { Text, View, StyleSheet } from 'react-native';

const PriceTag = ({ price, oldPrice }) => {
  return (
    &lt;View style={styles.container}&gt;
      {oldPrice && &lt;Text style={styles.oldPrice}&gt;{oldPrice} €&lt;/Text&gt;}
      &lt;Text style={[styles.price, oldPrice && styles.promotionPrice]}&gt;{price} €&lt;/Text&gt;
    &lt;/View&gt;
  );
};

const styles = StyleSheet.create({
  container: { flexDirection: 'row', alignItems: 'center', gap: 8 },
  oldPrice: { fontSize: 14, color: '#999', textDecorationLine: 'line-through' },
  price: { fontSize: 18, fontWeight: 'bold', color: '#333' },
  promotionPrice: { color: '#e53935', fontSize: 20 },
});

export default PriceTag;

import { View, Text, TouchableOpacity, StyleSheet } from 'react-native';

const QuantitySelector = ({ quantity, onQuantityChange }) => {
  const increment = () => quantity < 10 && onQuantityChange(quantity + 1);
  const decrement = () => quantity > 1 && onQuantityChange(quantity - 1);

  return (
    &lt;View style={styles.container}&gt;
      &lt;TouchableOpacity onPress={decrement} style={styles.button}&gt;
        &lt;Text style={styles.buttonText}&gt;-&lt;/Text&gt;
      &lt;/TouchableOpacity&gt;
      &lt;Text style={styles.quantity}&gt;{quantity}&lt;/Text&gt;
      &lt;TouchableOpacity onPress={increment} style={styles.button}&gt;
        &lt;Text style={styles.buttonText}&gt;+&lt;/Text&gt;
      &lt;/TouchableOpacity&gt;
    &lt;/View&gt;
  );
};

const styles = StyleSheet.create({
  container: { flexDirection: 'row', alignItems: 'center', gap: 12 },
  button: { backgroundColor: '#ddd', paddingHorizontal: 12, paddingVertical: 6, borderRadius: 6 },
  buttonText: { fontSize: 18, fontWeight: 'bold' },
  quantity: { fontSize: 16, fontWeight: '600', minWidth: 30, textAlign: 'center' },
});

export default QuantitySelector;

import { View, Text, Image, TouchableOpacity, StyleSheet, useState } from 'react-native';
import PriceTag from './PriceTag';
import QuantitySelector from './QuantitySelector';

const ProductCard = ({ name, image, price, oldPrice, onAddToCart }) => {
  const [quantity, setQuantity] = useState(1);

  return (
    &lt;View style={styles.card}&gt;
      &lt;Image source={{ uri: image }} style={styles.image} /&gt;
      &lt;Text style={styles.name}&gt;{name}&lt;/Text&gt;
      &lt;PriceTag price={price} oldPrice={oldPrice} /&gt;
      &lt;QuantitySelector quantity={quantity} onQuantityChange={setQuantity} /&gt;
      &lt;TouchableOpacity style={styles.addButton} onPress={() => onAddToCart(quantity)}&gt;
        &lt;Text style={styles.addButtonText}&gt;Ajouter au panier ({quantity})&lt;/Text&gt;
      &lt;/TouchableOpacity&gt;
    &lt;/View&gt;
  );
};

const styles = StyleSheet.create({
  card: { backgroundColor: '#fff', borderRadius: 12, padding: 12, margin: 8, shadow... },
  image: { width: '100%', height: 150, borderRadius: 8 },
  name: { fontSize: 16, fontWeight: '600', marginVertical: 8 },
  addButton: { backgroundColor: '#4CAF50', padding: 12, borderRadius: 8, marginTop: 8 },
  addButtonText: { color: '#fff', textAlign: 'center', fontWeight: 'bold' },
});

export default ProductCard;
